import {{ Injectable }} from '@nestjs/common';
import {{ QueueService }} from './models/queue.model';
import {{ QueueServiceRepository }} from './repositories/queue.repository';

@Injectable()
export class QueueServiceService {{
  constructor(
    private readonly repository: QueueServiceRepository,
  ) {{}}

  async findAll(): Promise<QueueService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<QueueService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<QueueService>): Promise<QueueService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<QueueService>): Promise<QueueService> {{
    return this.repository.update(id, data);
  }}
}}
